import java.io.BufferedReader;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Walsh {
	public static void main(String[] args) {
		try (Scanner read = new Scanner(new BufferedReader(
				new FileReader(new File("walsh.in"))))) {
			try {
				FileWriter outputFile = new FileWriter("walsh.out");
				int matrixElem;
				int n = read.nextInt();
				int k = read.nextInt();
				int x, y;
				/*
				 * citesc de la tastatura fiecare pereche (x,y)
				 * pentru fiecare pereche aplic functia care imi intoarce
				 * elementul de pe pozitia respectiva din matrice
				 */
				for (int i = 0; i < k; i++) {
					matrixElem = 0;
					x = read.nextInt();
					y = read.nextInt();
					outputFile.write(String.valueOf(getElem(n, x, y, matrixElem)) + '\n');
				}
				outputFile.close();
			} catch (IOException e1) {
				e1.printStackTrace();
			}
		} catch (FileNotFoundException e) {
			e.printStackTrace();
		}
	}

	/*
	 * pentru aflarea elementului din matrice, am folosit Divide et Impera,
	 * impartind problema in 4 subprobleme specifice fiecarui cadran
	 */
	static int getElem(int n, int x, int y, int matrixElem) {
		// cazul de baza se intalneste pentru n=2
		if (n == 2) {
			if (x == 1 && y == 1) {
				return matrixElem;
			}
			if (x == 1 && y == 2) {
				return matrixElem;
			}
			if (x == 2 && y == 1) {
				return matrixElem;
			}
			/*
			 * matrixElem ma ajuta sa pastrez elementele matricei, acesta porneste
			 * mereu de la 0 si cand ajung in cadranul 4 se neaga, in rest ramane la fel
			 */
			return matrixElem ^ 1;
		} else {
			// cadranul 1
			if (x >= 1 && x <= n / 2 && y >= 1 && y <= n / 2) {
				return getElem(n / 2, x, y, matrixElem);
			} else {
				// cadranul 3
				if (x >= 1 && x <= n / 2 && y >= (n / 2 + 1) && y <= n) {
					return getElem(n / 2, x, (y - n / 2), matrixElem);
				} else {
					// cadranul 2
					if (x >= (n / 2 + 1) && x <= n && y >= 1 && y <= n / 2) {
						return getElem(n / 2, (x - n / 2), y, matrixElem);
					} else {
						// cadranul 4
						matrixElem ^= 1;
						return getElem(n / 2, (x - n / 2), (y - n / 2), matrixElem);
					}
				}
			}
		}
	}
}

#include <iostream>
#include <fstream>

using namespace std;

int FindElement(bool isIn4thQuadrant, int N, int x, int y) {
    // cazul de baza - tabela W1; verificam daca este indeplinit
    if (N == 1) {
        if (isIn4thQuadrant)
            return 1;
        else
            return 0;
    }

    // apelam functia in functie de cadranul in care ne aflam, impartind n la 2
    // cadranul 1
    if (x <= N/2 && y <= N/2)
        return FindElement(isIn4thQuadrant, N/2, x, y);

    // cadranul 2
    else if (x <= N/2 && y > N/2)
        return FindElement(isIn4thQuadrant, N/2, x, y - N/2);

    // cadranul 3
    else if (x > N/2 && y <= N/2)
        return FindElement(isIn4thQuadrant, N/2, x - N/2, y);

    // cadranul 4
    else if (x > N/2 && y > N/2)
        return FindElement(!isIn4thQuadrant, N/2, x - N/2, y - N/2);
}

// functie care returneaza elementul din tabela Walsh de la pozitia (x, y)
int FindElementAtIndex(int N, int x, int y) {
    return FindElement(false, N, x, y);
}

int main() {
    // sunt declarate stream-urile de input si de output
    fstream input, output;
    input.open("walsh.in");
    output.open("walsh.out");

    // declaram si citim variabilele
    int N, K, x, y;
    input >> N >> K;

    for (int i = 0; i < K; ++i) {
        input >> x >> y;
        output << FindElementAtIndex(N, x, y) << endl;
    }

    // dupa ce am afisat raspunsul, inchidem stream-urile
    input.close();
    output.close();
    return 0;
}
